const { exec } = require('child_process');
const sharp = require('sharp');
const {Log,Str,Num,Obj}=require("biz9-utility");
const {DataItem,DataType,Type}=require("biz9-logic");
class Image_Cloud_Flare {
	static get_batch_token = (account_id,api_token) => {
        return new Promise((callback) => {
            let data_batch,error=null;
            const url = "https://api.cloudflare.com/client/v4/accounts/"+account_id+"/images/v1/batch_token";
            const headers = {
                "Accept": "application/json",
                "Authorization": "Bearer " +api_token
            };
            let curlCommand = `curl -s -H "Accept: ${headers.Accept}"`;
            if (headers.Authorization) {
                curlCommand += ` -H "Authorization: ${headers.Authorization}"`;
            }
            curlCommand += ` "${url}"`;
            exec(curlCommand,async(err,stdout,stderr) => {
                if (err) {
                    console.error(err);
                    Log.append(error,"1 Error executing curl command:"+ err.message);
                    callback([error,null]);
                   }
                if (stderr) {
                    console.error(err);
                    Log.append(error,"2 Curl stderr: "+stderr);
                    callback([error,null]);
                   }
                try {
                    const jsonData =await JSON.parse(stdout);
                    data_batch =  jsonData.result.token;
                    if(data_batch!== null){
                        callback([error,data_batch]);
                    }
                } catch (parseError) {
                    console.error("Error parsing JSON response:"+ parseError.message);
                    console.log('Raw Response:', stdout);
                    callback([parseError,null]);
                }
            });
        });
    };
 	static post_batch_image = (api_token,batch_token,image_filename,item_file_path) => {
        let error = null;
        return new Promise((callback) => {
            async.series([
                async function(call){
                    const post_url = "https://batch.imagedelivery.net/images/v1";
                    const headers = {
                        "Accept": "application/json",
                        "Authorization": "Bearer " +batch_token
                    };
                    let curlCommand = `curl -s -H "Accept: ${headers.Accept}"`;
                    curlCommand += ` -H "Authorization: ${headers.Authorization}"`;
                    curlCommand += " -H X-Auth-Key: "+ api_token;
                    curlCommand += " -F requireSignedURLs=false";
                    curlCommand += " -F id="+image_filename;
                    curlCommand += " -F file=@"+item_file_path;
                    curlCommand += ` "${post_url}"`;
                    exec(curlCommand, (err, stdout, stderr) => {
                        if (err) {
                            err = `Error executing curl command: ${err.message}`;
                            console.error(err);
                            error=Log.append(error,err);
                        }
                        if (stderr) {
                            err = `Curl stderr: ${stderr}`;
                            console.error(err);
                            error=Log.append(error,err);
                        }
                        try {
                            const jsonData = JSON.parse(stdout);
                            console.log('cool');
                            console.log(jsonData);
                            console.log('bean');
                            if(jsonData!== null){
                                callback([error,jsonData]);
                            }
                        } catch (parseError) {
                            console.error(`Error parsing JSON response: ${parseError.message}`);
                            console.log('Raw Response:', stdout);
                            error=Log.append(error,parseError);
                            callback([error,null]);
                        }
                    });
                },
            ])
        });
    };
}
class Image_File {
	static get_new_by_base64 = (base64) =>{
		return DataItem.get_new(DataType.IMAGE,0,
			{
				extension:!Str.check_is_null(Str.get_file_type_from_base64(base64)) ? Str.get_file_type_from_base64(base64).extension : 'jpeg',
				image_filename:!Str.check_is_null(Str.get_file_type_from_base64(base64)) ? Str.get_guid()+"."+Str.get_file_type_from_base64(base64).extension : 'not_found.jpeg',
				buffer:!Str.check_is_null(Str.get_file_type_from_base64(base64)) ? Buffer.from(base64.split(';base64,').pop(), 'base64') : null,
		});
	}
  	static post_write = (buffer,size,path_filename,type_resize) => {
        return new Promise((callback) => {
            let data,error=null;
            switch(type_resize){
            case Type.IMAGE_RESIZE_NONE:
            sharp(buffer)
                .toFile(path_filename,(err, info) => {
                    if(err){
                        error=Log.append(error,'Error thumb saving file:');
                        console.error('Error thumb saving file:', err);
                    }
                    if(info!==null){
                        callback([error,true]);
                    }
                });
            break;
            case Type.IMAGE_RESIZE_NORMAL:
            sharp(buffer)
                .resize(size)
                .toFile(path_filename,(err, info) => {
                    if(err){
                        error=Log.append(error,'Error thumb saving file:');
                        console.error('Error thumb saving file:', err);
                    }
                    if(info!==null){
                        callback([error,true]);
                    }
                });
            break;
            case Type.IMAGE_RESIZE_SQUARE:
            sharp(buffer)
                .resize(size,size,{fit:sharp.fit.fill,quality:100})
                .toFile(path_filename,(err, info) => {
                    if(err){
                        error=Log.append(error,'Error thumb saving file:');
                        console.error('Error thumb saving file:', err);
                    }
                    if(info!==null){
                        callback([error,true]);
                    }
                });
                break;
        }
        });
	}
}
module.exports = {
	Image_Cloud_Flare,
	Image_File,
};
